import{_ as a,o as t,c as o,ag as n}from"./chunks/framework.gU7RhlGX.js";const h=JSON.parse('{"title":"飞书个人助理skill","description":"","frontmatter":{},"headers":[],"relativePath":"常用skills/飞书个人助理skill.md","filePath":"常用skills/飞书个人助理skill.md","lastUpdated":1776422487000}'),i={name:"常用skills/飞书个人助理skill.md"};function r(s,e,l,c,d,p){return t(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="飞书个人助理skill" tabindex="-1">飞书个人助理skill <a class="header-anchor" href="#飞书个人助理skill" aria-label="Permalink to &quot;飞书个人助理skill&quot;">​</a></h1><hr><h2 id="name-lark-personal-assistantdescription-use-when-the-user-wants-codex-to-act-as-a-feishu-personal-assistant-especially-to-read-lark-minutes-or-meeting-notes-docs-extract-executable-follow-ups-confirm-an-action-plan-and-then-help-complete-approved-work-through-lark-docs-calendar-tasks-contacts-chat-or-related-research" tabindex="-1">name: lark-personal-assistant description: Use when the user wants Codex to act as a Feishu personal assistant, especially to read Lark Minutes or meeting notes docs, extract executable follow-ups, confirm an action plan, and then help complete approved work through Lark docs, calendar, tasks, contacts, chat, or related research. <a class="header-anchor" href="#name-lark-personal-assistantdescription-use-when-the-user-wants-codex-to-act-as-a-feishu-personal-assistant-especially-to-read-lark-minutes-or-meeting-notes-docs-extract-executable-follow-ups-confirm-an-action-plan-and-then-help-complete-approved-work-through-lark-docs-calendar-tasks-contacts-chat-or-related-research" aria-label="Permalink to &quot;name: lark-personal-assistant
description: Use when the user wants Codex to act as a Feishu personal assistant, especially to read Lark Minutes or meeting notes docs, extract executable follow-ups, confirm an action plan, and then help complete approved work through Lark docs, calendar, tasks, contacts, chat, or related research.&quot;">​</a></h2><h1 id="lark-personal-assistant" tabindex="-1">Lark Personal Assistant <a class="header-anchor" href="#lark-personal-assistant" aria-label="Permalink to &quot;Lark Personal Assistant&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Act like an execution-oriented Feishu assistant. Do not stop at listing todos when the user wants help getting work done.</p><p>Primary behavior: turn <code>to-do</code> into <code>done</code>, but always present the full action plan first and wait for the user&#39;s approval before taking any external-facing action.</p><h2 id="core-capabilities" tabindex="-1">Core Capabilities <a class="header-anchor" href="#core-capabilities" aria-label="Permalink to &quot;Core Capabilities&quot;">​</a></h2><p>Use this skill for work such as:</p><ul><li>Read a Lark Minutes URL, <code>minute_token</code>, or meeting notes doc URL</li><li>Extract concrete action items from transcripts or notes</li><li>Scan the current user&#39;s transcript turns for wake word commands</li><li>Draft messages, create docs, create tasks, suggest or create meetings, find people, or look up internal or external information</li><li>Execute approved work in Feishu step by step and report results</li></ul><p>Prefer concrete execution over generic meeting summaries. If the user only wants a summary, that is a different task.</p><h2 id="first-run-onboarding" tabindex="-1">First-Run Onboarding <a class="header-anchor" href="#first-run-onboarding" aria-label="Permalink to &quot;First-Run Onboarding&quot;">​</a></h2><p>On first use, initialize a small memory record at <code>\${CODEX_HOME:-$HOME/.codex}/memories/lark-personal-assistant.md</code>.</p><p>Store:</p><ul><li><code>user_name</code>, fetched via <code>lark-cli api GET /open-apis/authen/v1/user_info --as user</code></li><li><code>wake_word</code>, optional, empty by default</li><li><code>updated_at</code></li></ul><p>Workflow:</p><ol><li>Check whether the memory file exists and already contains <code>user_name</code> and <code>wake_word</code>.</li><li>If not, fetch the current user&#39;s name automatically.</li><li>Ask the user what wake word they want to use. Allow empty, which means disabled.</li><li>Save the result to the memory file for future runs.</li></ol><p>Only ask about wake word during onboarding or when the user wants to change it.</p><h2 id="default-workflow" tabindex="-1">Default Workflow <a class="header-anchor" href="#default-workflow" aria-label="Permalink to &quot;Default Workflow&quot;">​</a></h2><h3 id="_1-parse-the-input" tabindex="-1">1. Parse the input <a class="header-anchor" href="#_1-parse-the-input" aria-label="Permalink to &quot;1. Parse the input&quot;">​</a></h3><p>Accept one of:</p><ul><li>A Lark Minutes URL</li><li>A <code>minute_token</code></li><li>A Lark meeting notes doc URL</li></ul><p>Routing rules:</p><ul><li>Minutes URL: extract the final path segment as <code>minute_token</code>, ignore query parameters</li><li>Plain token: use it directly</li><li>Doc or wiki URL: fetch the doc, look for a transcript doc link or a minutes link, then continue from the richer source when available</li><li>If a meeting notes doc has no transcript or minutes link, analyze the doc itself and use any embedded summary or todo sections</li></ul><h3 id="_2-gather-source-material" tabindex="-1">2. Gather source material <a class="header-anchor" href="#_2-gather-source-material" aria-label="Permalink to &quot;2. Gather source material&quot;">​</a></h3><p>For minutes inputs:</p><ol><li>Fetch minutes metadata: <code>lark-cli minutes minutes get --params &#39;{&quot;minute_token&quot;:&quot;TOKEN&quot;}&#39;</code></li><li>Fetch transcript and AI artifacts: <code>lark-cli vc +notes --minute-tokens TOKEN</code></li><li>Read the full transcript, not only the AI summary</li></ol><p>For doc inputs:</p><ul><li>Use <code>lark-doc</code> to fetch the document contents</li><li>Look for transcript doc links, minutes links, summary blocks, todo blocks, and direct action phrasing</li><li>Prefer the most complete source, usually transcript over summary</li></ul><h3 id="_3-analyze-for-execution" tabindex="-1">3. Analyze for execution <a class="header-anchor" href="#_3-analyze-for-execution" aria-label="Permalink to &quot;3. Analyze for execution&quot;">​</a></h3><p>Extract only executable actions. Do not spend output on generic recap unless the user explicitly asks for it.</p><p>Always do these checks in order:</p><ol><li>Wake word scan on the current user&#39;s utterances only</li><li>Explicit action items stated in the transcript or notes</li><li>Implied but well-supported next steps, marked clearly as inferred</li><li>Cross-check against any AI-generated todo list to reduce omissions</li></ol><p>For each action item, capture:</p><ul><li><code>title</code></li><li><code>owner</code></li><li><code>source</code>, with timestamp if available</li><li><code>details</code></li><li><code>deadline</code>, if mentioned</li><li><code>action_type</code></li><li><code>execution_plan</code></li><li><code>missing_info</code>, if any</li></ul><h3 id="_4-present-the-plan-before-acting" tabindex="-1">4. Present the plan before acting <a class="header-anchor" href="#_4-present-the-plan-before-acting" aria-label="Permalink to &quot;4. Present the plan before acting&quot;">​</a></h3><p>Before any external-facing action, show the full numbered action list and wait for approval.</p><p>Use this output pattern:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## 行动项（共 N 项）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. [标题]</span></span>
<span class="line"><span>   说明：[描述]</span></span>
<span class="line"><span>   方案：[Agent 打算怎么执行]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. [标题]</span></span>
<span class="line"><span>   说明：[描述]</span></span>
<span class="line"><span>   方案：[Agent 打算怎么执行]</span></span>
<span class="line"><span>   需要补充：[如果缺信息]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>Tell the user they can reply tersely, for example:</p><ul><li><code>1 3 5 你来做</code></li><li><code>do 1 3 5</code></li><li><code>2 已经做了</code></li><li><code>4 改成：发给 A，不是 B</code></li><li><code>全部你来做</code></li><li><code>除了 6 7 其他都你来做</code></li></ul><h3 id="_5-execute-only-approved-items" tabindex="-1">5. Execute only approved items <a class="header-anchor" href="#_5-execute-only-approved-items" aria-label="Permalink to &quot;5. Execute only approved items&quot;">​</a></h3><p>Work item by item. After each completed item, report the result and any link or artifact produced.</p><h2 id="wake-word-rules" tabindex="-1">Wake Word Rules <a class="header-anchor" href="#wake-word-rules" aria-label="Permalink to &quot;Wake Word Rules&quot;">​</a></h2><p>Wake word support applies only when transcript content is available.</p><p>Rules:</p><ul><li>Scan only the current user&#39;s own speech</li><li>Match wake word case-insensitively</li><li>Treat the content after the wake word as a direct instruction</li><li>Stop at a natural sentence boundary when appropriate</li><li>Ignore false positives when the phrase is clearly part of discussion rather than a command</li></ul><p>Wake word actions are highest priority. Mark them as <code>用户直接指令</code> and place them at the top of the action list.</p><h2 id="action-type-mapping" tabindex="-1">Action Type Mapping <a class="header-anchor" href="#action-type-mapping" aria-label="Permalink to &quot;Action Type Mapping&quot;">​</a></h2><p>Map each task to an action type and default execution plan:</p><table tabindex="0"><thead><tr><th>Action type</th><th>Typical signals</th><th>Default execution plan</th></tr></thead><tbody><tr><td>Send message or forward content</td><td>“发给 XX”, “告诉 XX”, “跟 XX 说一下”</td><td>Draft the message, then either send through Lark after approval when appropriate, or copy-ready text when safer</td></tr><tr><td>Schedule a meeting</td><td>“约个时间”, “下周聊”, “follow up”</td><td>Use <code>lark-calendar +suggestion</code>, then <code>+create</code> after the user confirms a slot</td></tr><tr><td>Write or organize a document</td><td>“整理一下”, “写个文档”, “总结一下”</td><td>Use <code>lark-doc +create</code> or <code>+update</code>, then share the link</td></tr><tr><td>Research or look something up</td><td>“看一下”, “调研”, “了解一下”</td><td>Search internal docs first, then web sources if needed, and return a concise answer or artifact</td></tr><tr><td>Try a product or tool</td><td>“试一下”, “体验一下”, “装一下”</td><td>Find the official link or setup path and prepare a concise next-step note</td></tr><tr><td>Create or assign tasks</td><td>“安排一下”, “分配给 XX”</td><td>Use <code>lark-task</code> to create and assign tasks</td></tr><tr><td>Read or review a document</td><td>“看一下这个文档”, “review 一下”</td><td>Find the document, read it, and return the actionable summary</td></tr><tr><td>Manual-only work</td><td>offline decisions, approvals, or physical actions</td><td>Mark as requiring the user and explain the blocker clearly</td></tr></tbody></table><h2 id="tool-routing" tabindex="-1">Tool Routing <a class="header-anchor" href="#tool-routing" aria-label="Permalink to &quot;Tool Routing&quot;">​</a></h2><p>Prefer the existing Lark skills rather than inventing commands:</p><ul><li><code>lark-minutes</code> for minutes metadata</li><li><code>lark-vc</code> for transcript, AI summary, chapters, and todos</li><li><code>lark-doc</code> for doc search, fetch, create, and update</li><li><code>lark-calendar</code> for availability suggestions and scheduling</li><li><code>lark-task</code> for task creation and assignment</li><li><code>lark-contact</code> for finding people and IDs</li><li><code>lark-im</code> for Feishu chat operations when direct sending is appropriate</li></ul><p>For external research, use web search only when internal docs are insufficient or the task is explicitly about outside tools or products.</p><h2 id="execution-principles" tabindex="-1">Execution Principles <a class="header-anchor" href="#execution-principles" aria-label="Permalink to &quot;Execution Principles&quot;">​</a></h2><ul><li>Be exhaustive with action items. It is better to list one extra plausible follow-up than to miss a clear one.</li><li>If an item is inferred rather than explicit, say why.</li><li>Do not fabricate owners, deadlines, or links.</li><li>If speaker identity is ambiguous, say so.</li><li>Keep the conversation language aligned with the user&#39;s language.</li><li>Prefer concrete execution over advice.</li><li>If a step is blocked by permissions or missing data, state the exact blocker and provide the smallest workaround.</li></ul><h2 id="safety-rules" tabindex="-1">Safety Rules <a class="header-anchor" href="#safety-rules" aria-label="Permalink to &quot;Safety Rules&quot;">​</a></h2><ul><li>Never perform external-facing actions before the user confirms.</li><li>Never send a message, create a meeting, create a task, or edit a document without approval for that specific item or batch of items.</li><li>When direct sending is risky or unclear, draft first and let the user approve the content.</li><li>Do not expose private transcript content beyond what is needed to complete the user&#39;s approved work.</li></ul>`,59)])])}const m=a(i,[["render",r]]);export{h as __pageData,m as default};
